      "keystrokes": "cat > /tmp/test.vim << 'EOF'\ncall setreg('a', ':s/^\\(.*\\)\\s*,\\s*\\(.*\\)\\s*,\\s*\\(.*\\)$/\\U\\3;\\U\\2;\\U\\1;OK\\r')\n%normal! @a\n:wq\nEOF\n",
